    ],
    source_path: '',
    ...overrides,
  }
}

function makeManifest(overrides: Partial<ManifestEntry> = {}): ManifestEntry {
  return {
    client: 'codex',
    project: 'test-project',
    session_id: 'test-session',
    raw_sha256: 'abcdef1234567890abcdef1234567890abcdef1234567890abcdef1234567890',
